#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        if (K > N) {
            printf("%d\n", N);
            continue;
        }
        int best = 0;
        for (int i = 1; i <= K; ++i) {
            int r = N % i;
            if (r > best) best = r;
        }
        printf("%d\n", best);
    }
    return 0;
}

